import{_ as a,o,c as t,a3 as n}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"159. Senior Allowance","description":"","frontmatter":{"title":"159. Senior Allowance","eba":"Mental Health Services 2024-2028","topics":["allowances","classifications"]},"headers":[],"relativePath":"ebas/mental-health/support-services/preliminary/159-senior-allowance.md","filePath":"ebas/mental-health/support-services/preliminary/159-senior-allowance.md"}'),r={name:"ebas/mental-health/support-services/preliminary/159-senior-allowance.md"};function i(l,e,s,p,c,d){return o(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="_159-senior-allowance" tabindex="-1">159. Senior Allowance <a class="header-anchor" href="#_159-senior-allowance" aria-label="Permalink to &quot;159. Senior Allowance&quot;">​</a></h1><p><strong>159.1</strong> An Employee who is appointed as a Senior will have their classification preceded by the word Senior and shall be paid an allowance of 10 per cent of the base rate payable for their classification pursuant to <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>.</p><p><strong>159.2</strong> Appointment to a position preceded by the word Senior will only be made where the work performed by such Employee represents a net addition to the work value of the substantive role in a similar area or areas. Indicia of a new addition to work value may include:</p><p><strong>(a)</strong> the performance of additional duties or functions</p><p><strong>(b)</strong> the assignment of a special project; or</p><p><strong>(c)</strong> an increased emphasis on the performance of core functions already undertaken by Employees in the relevant classification.</p><p><strong>159.3</strong> A net addition to the work value of the substantive role of an Employee would be characterised by the following:</p><p><strong>(a)</strong> the additional functions or duties are a regular and ongoing requirement; and</p><p><strong>(b)</strong> experience in the role commensurate with this clause, coupled with on-the-job training where provided by the Employer; and</p><p><strong>(c)</strong> the necessity for additional training in a particular aspect of the role above that which is required to fulfil the role of an Employee employed in a similar area(s); and</p><p><strong>(d)</strong> a greater level of judgement is required from the Employee, whereby they are capable of making independent decisions to a degree not generally expected of an Employee employed in a similar area(s); and</p><p><strong>(e)</strong> a higher degree of accountability is expected for work undertaken, such that the Employee is clearly performing at a level above that of their peers employed in a similar area(s) by the Employer.</p><p><strong>159.4</strong> The Senior Allowance shall be additional to any other allowance to which the Employee is entitled under Section 4.</p>',13)])])}const f=a(r,[["render",i]]);export{m as __pageData,f as default};
